import{_ as e,o as s,c as t,ai as r}from"./chunks/framework.CaiDwmc7.js";const p=JSON.parse('{"title":"Redis 事务与发布订阅","description":"","frontmatter":{},"headers":[],"relativePath":"redis/transaction-pubsub.md","filePath":"redis/transaction-pubsub.md"}'),d={name:"redis/transaction-pubsub.md"};function i(n,o,l,c,a,g){return s(),t("div",null,[...o[0]||(o[0]=[r('<h1 id="redis-事务与发布订阅" tabindex="-1">Redis 事务与发布订阅 <a class="header-anchor" href="#redis-事务与发布订阅" aria-label="Permalink to “Redis 事务与发布订阅”">​</a></h1><hr><h3 id="❓-面试官-redis-的事务跟-mysql-的事务有什么区别-它支持回滚吗" tabindex="-1">❓ 面试官：Redis 的事务跟 MySQL 的事务有什么区别？它支持回滚吗？ <a class="header-anchor" href="#❓-面试官-redis-的事务跟-mysql-的事务有什么区别-它支持回滚吗" aria-label="Permalink to “❓ 面试官：Redis 的事务跟 MySQL 的事务有什么区别？它支持回滚吗？”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> Redis 的事务<strong>非常弱</strong>，跟 MySQL 的 ACID 事务完全不是一个级别。<strong>它不支持原子性的回滚（Rollback）</strong>。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><strong>如何开启和执行</strong>： <ul><li>客户端发送 <code>MULTI</code> 开启事务。</li><li>接着发送各种读写命令（比如 <code>SET</code>、<code>INCR</code>），Redis 此时不会立刻执行，而是把这些命令放进一个<strong>队列</strong>里。</li><li>最后发送 <code>EXEC</code>，Redis 就会按顺序依次执行队列里的所有命令。</li></ul></li><li><strong>为什么不支持回滚？</strong>： <ul><li><strong>语法错误（组队时报错）</strong>：如果你在 <code>MULTI</code> 之后敲错了一个不存在的命令（比如 <code>SEET a 1</code>），整个队列会在 <code>EXEC</code> 时被直接丢弃，所有命令都不执行。这勉强算是一种“原子性保护”。</li><li><strong>运行错误（执行时报错）</strong>：这是最坑的。比如你对一个 String 类型的 Key 故意执行了只支持 List 的 <code>LPUSH</code> 命令，Redis 在组队时根本发现不了（语法是对的）。直到 <code>EXEC</code> 真正执行时，碰到 <code>LPUSH</code> 报错了，<strong>Redis 会继续往下执行队列里剩下的正确命令！而之前已经执行成功的命令，绝对不会回滚！</strong></li></ul></li><li><strong>官方的解释</strong>： <ul><li>Redis 作者认为，支持回滚需要极其复杂的内部机制（像 MySQL 的 undo log），这会严重拖慢 Redis 简单极致的性能。而且这种“运行错误”通常是程序员写出了 Bug 造成的，不应该由数据库的底层引擎来兜底。</li></ul></li></ol><p><strong>🌟 面试加分项（替代方案）：</strong> 面试官常追问：“那如果我的业务真的强依赖多个命令的原子性操作怎么办？” <strong>答</strong>：在现在的企业开发中，<strong>几乎没人再用 <code>MULTI</code> / <code>EXEC</code> 原生事务了</strong>。 替代方案是<strong>使用 Lua 脚本</strong>。Redis 保证在执行 Lua 脚本期间，整个服务器是阻塞的（单线程），其他任何客户端的命令都插不进来，这就完美实现了真正的“原子性”。（这也是分布式锁 Redisson 底层大量使用的技术）。</p><hr><h3 id="❓-面试官-redis-里的-watch-机制-乐观锁-是怎么回事-【中级】" tabindex="-1">❓ 面试官：Redis 里的 Watch 机制（乐观锁）是怎么回事？【中级】 <a class="header-anchor" href="#❓-面试官-redis-里的-watch-机制-乐观锁-是怎么回事-【中级】" aria-label="Permalink to “❓ 面试官：Redis 里的 Watch 机制（乐观锁）是怎么回事？【中级】”">​</a></h3><p><em>频率：🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong><code>WATCH</code> 是 Redis 配合事务 <code>MULTI</code> 使用的一种<strong>乐观锁机制（CAS）</strong>。它用于在事务开启之前，监控一个或多个 Key 是否被其他客户端偷偷改动过。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><strong>使用场景</strong>：比如两个客户端同时想执行 <code>INCR balance</code>（给账户余额加 1）。</li><li><strong>操作步骤</strong>： <ul><li>客户端 A 在开启事务前先执行：<code>WATCH balance</code>。</li><li>客户端 A 接着执行 <code>MULTI</code> -&gt; <code>INCR balance</code> -&gt; <code>EXEC</code>。</li></ul></li><li><strong>核心原理</strong>： <ul><li>在 A 执行 <code>EXEC</code> 的那一瞬间，Redis 会去检查 <code>balance</code> 这个 Key 的版本号。</li><li>如果发现就在 A <code>WATCH</code> 之后、<code>EXEC</code> 之前这段时间里，有另一个客户端 B 偷偷改了 <code>balance</code> 的值。</li><li>Redis 就会<strong>直接中止 A 的整个事务</strong>（<code>EXEC</code> 返回 nil），A 的所有命令全部失败。</li><li>A 只能无奈地自己写个 <code>while(true)</code> 循环重新去 <code>WATCH</code> 并重试。</li></ul></li></ol><hr><h3 id="❓-面试官-你了解-redis-的-pub-sub-发布订阅-功能吗-它能当做消息队列-mq-来用吗-【中级】" tabindex="-1">❓ 面试官：你了解 Redis 的 Pub/Sub（发布订阅）功能吗？它能当做消息队列（MQ）来用吗？【中级】 <a class="header-anchor" href="#❓-面试官-你了解-redis-的-pub-sub-发布订阅-功能吗-它能当做消息队列-mq-来用吗-【中级】" aria-label="Permalink to “❓ 面试官：你了解 Redis 的 Pub/Sub（发布订阅）功能吗？它能当做消息队列（MQ）来用吗？【中级】”">​</a></h3><p><em>频率：🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 发布订阅是一种消息广播机制。<strong>千万不要把 Redis 的 Pub/Sub 当作企业级的消息队列来用！</strong> 因为它最大的致命伤是<strong>“发后即忘”（Fire-and-forget）</strong>，消息极度容易丢失。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><strong>怎么用？</strong>： <ul><li>消费者打开一个终端：<code>SUBSCRIBE channel_1</code>（订阅频道 1）。</li><li>生产者打开另一个终端：<code>PUBLISH channel_1 &quot;hello&quot;</code>（向频道 1 发消息）。</li><li>消费者立刻就能收到 &quot;hello&quot;。</li></ul></li><li><strong>为什么不能当 MQ 用？（三大致命缺陷）</strong>： <ul><li><strong>消息丢失 1（消费者不在线）</strong>：如果没有任何消费者订阅这个频道，或者消费者网络断了，你 <code>PUBLISH</code> 的消息会被 Redis 直接丢进垃圾桶。等消费者连上线后，历史消息绝对找不回来。</li><li><strong>消息丢失 2（积压问题）</strong>：即使消费者在线，如果生产者发消息的速度远超消费者处理的速度，导致输出缓冲区塞满，Redis 为了保护自己不死掉，会无情地踢掉这个消费者连接，消息依然丢失。</li><li><strong>没有持久化</strong>：所有的发布订阅消息只存在于内存的临时中转区，根本不会写进 RDB 或 AOF 日志里。</li></ul></li></ol><p><strong>🌟 面试加分项（实战架构演进）：</strong> 面试官可能会问：&quot;既然 Pub/Sub 这么废，那 Redis 5.0 为什么又出了个 <code>Stream</code> 数据结构？&quot; <strong>绝杀回答</strong>： &quot;<code>Stream</code> 才是 Redis 官方推出的真正用来做消息队列的终极武器！ 它不仅支持消费组（Consumer Group）、支持消息持久化（存入 RDB/AOF 不丢失）、支持类似 Kafka 的 <code>ACK</code> 确认机制。 但即便如此，在真正的海量高并发业务（如订单交易流转）中，我们依然推荐使用专业的 RabbitMQ 或 RocketMQ。Redis Stream 更适合中小规模、轻量级的异步解耦任务。&quot;</p>',21)])])}const R=e(d,[["render",i]]);export{p as __pageData,R as default};
